// package-lock.json generation script

const fs = require('fs');
const path = require('path');

function generatePackageLock() {
  const originalPkgFile = 'package.json';
  const lockFilePath = 'package-lock.json';

  // Create a copy of the original package.json file
  const newPkgFileContent = JSON.parse(fs.readFileSync(originalPkgFile, 'utf8'));
  fs.writeFileSync(lockFilePath, JSON.stringify(newPkgFileContent, null, 2));

  // Read the lock file and update dependencies to be exact versions
  const lockFileContent = JSON.parse(fs.readFileSync(lockFilePath, 'utf8'));
  Object.keys(lockFileContent.dependencies).forEach((packageName) => {
    lockFileContent.dependencies[packageName] = { version: fs.readFileSync(path.join(originalPkgFile), 'utf8').replace(packageName + ': ', '').trim() };
  });

  // Write the updated content back to the lock file
  fs.writeFileSync(lockFilePath, JSON.stringify(lockFileContent, null, 2));
}

// Run the function to generate package-lock.json on every deployment
generatePackageLock();